class Admin_Model_Order extends Admin_Model_Base_Order {

    /**
     * @param Doctrine_Connection|null $conn
     */
    public function save(Doctrine_Connection $conn = null) {
        if ($this->ID == null) {
            $this->Date = date('Y-m-d');
            $this->Time = date('H:i');
            $this->Folder = generateRandomString(16);
            $this->InPohoda = 0;

            parent::save($conn);

            $this->OrderNumber = self::updateOrderNumber();
            parent::save($conn);

            $cart = Cart::getInstance();
            $this->TotalWeight = $cart->getTotalWeight();
            $this->applyCoupon($cart);

            foreach ($cart->getCartItems() as $cartItem) {
                OrderItem::createOrderItem($this->ID, $cartItem);
                Product::updateStockAfterOrder($cartItem);
            }
            OrderState::createOrderState($this->ID, OrderStateType::ID_STATE_NEW);
        }
        $this->DateTimeUpdated = date('Y-m-d H:i:s');

        parent::save($conn);
    }

    /**
     * @param Doctrine_Connection|null $conn
     */
    public function saveApiOrder($orderItems, Doctrine_Connection $conn = null) {
        if ($this->ID == null) {
            $this->Date = date('Y-m-d');
            $this->Time = date('H:i');
            $this->Folder = generateRandomString(16);
            $this->InPohoda = 0;

            parent::save($conn);

            $this->OrderNumber = self::updateOrderNumber();
            parent::save($conn);

            $cart = Cart::getInstance();
            $this->TotalWeight = $cart->getTotalWeight();

            foreach ($orderItems as $orderItem) {
                OrderItem::createOrderItem($this->ID, $orderItem, true);
                Product::updateStockAfterOrder($orderItem);
            }

            OrderState::createOrderState($this->ID, OrderStateType::ID_STATE_NEW);
        }

        parent::save($conn);
    }

    /**
     * @param $event
     */
    public function preSave($event) {
        parent::preSave($event);

        $modified = array_keys($this->getModified());
        $priceEdit = false;

        foreach ($modified as $property) {
            if (str_contains(strtolower($property), 'price')) {
                $priceEdit = true;
                break;
            }
        }

        if ($priceEdit) {
            $this->PriceTotalWithoutVat =  (float) $this->PriceProductWithoutVat + (float) $this->PriceShippingWithoutVat + (float) $this->PricePaymentWithoutVat;
            $this->PriceTotalWithVat = (float) $this->PriceProductWithVat + (float) $this->PriceShippingWithVat + (float) $this->PricePaymentWithVat;
        }
    }

    /**
     * @param bool $skipSave
     */
    public function updateItemPrices(bool $skipSave = false) {
        $this->PriceProductWithoutVat = 0;
        $this->PriceProductWithVat = 0;

        foreach ($this->orderItems as $orderItem) {
            $this->PriceProductWithoutVat += $orderItem->PriceWithoutVat * $orderItem->Quantity;
            $this->PriceProductWithVat += $orderItem->PriceWithVat * $orderItem->Quantity;
        }

        if ( !$skipSave )
            $this->save();
    }

    /**
     * @return string
     */
    public function updateOrderNumber(): string {
        $orderNumber = date('y') . date('m') . '00000';

        return (float) $orderNumber + $this->ID;
    }

    /**
     * @return void
     */
    public function updateInvoiceNumber() {
        $invoiceNumber = '8900000';

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Order object');
        $query->where('object.InvoiceNumber IS NOT NULL');
        $maxInvoiceNumber = $query->count();

        $this->InvoiceNumber = (float) $invoiceNumber + $maxInvoiceNumber + 1;
        $this->save();
    }

    /**
     * Lze stále editovat produkty?
     * @param $ID
     * @return bool
     */
    public static function canEditProducts($ID): bool {
        if (empty($ID))
            return false;

        $order = self::getOrder($ID);

        if (!$order)
            return false;

        if ($order->DatePayed)
            return false;

        if (in_array($order->OrderStateType_ID, [
            OrderStateType::ID_STATE_FINISH,
            OrderStateType::ID_STATE_DISTRIBUTED,
            OrderStateType::ID_STATE_PAYMENT_ACCEPTED,
            OrderStateType::ID_STATE_TAKEN,
            OrderStateType::ID_STATE_CANCEL,
        ]))
            return false;

        return true;
    }

    /**
