    public static function getLastOrders(int $limit = 10): array {
        $query = Doctrine_Query::create();
        $query->from("Admin_Model_Order object");
        $query->leftJoin("object.eshop eshop");
        $query->leftJoin("object.orderItems orderItems");
        $query->leftJoin("object.orderStateType orderStateType");
        $query->leftJoin("orderStateType.orderStateTypeLangs orderStateTypeLangs");
        $query->orderBy('object.ID DESC');

        if (!UserAdminSession::isAdmin())
            $query->andWhere('object.User_ID = ?', UserAdminSession::getCurrentUserID());
        elseif ($eshops = UserAdminSession::getCurrentUserEshop(true))
            $query->andWhere('object.Eshop_ID IN (' . implode(',', $eshops) . ')');

        $query->limit($limit);

        return $query->execute()->toArray();
    }

