    /**
     * @param int $ID
     * @return array
     */
    public static function getOrderByID(int $ID): array {
        $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Order object');
        $query->where('object.ID = ?', $ID);
        $query->leftJoin('object.invoiceAddress invoiceAddress');
        $query->leftJoin('object.currency currency');
        $query->leftJoin('object.deliveryAddress deliveryAddress');
        $query->leftJoin('object.orderStates orderStates');
        $query->leftJoin('orderStates.orderStateType orderStatesType');
        $query->leftJoin('object.orderStateType orderStateType');
        $query->leftJoin('orderStateType.orderStateTypeLangs orderStateTypeLangs');
        $query->leftJoin('object.orderItems orderItems');
        $query->leftJoin('object.shipping shipping');
        $query->leftJoin('object.payment payment');
        $query->leftJoin('orderItems.product product');
        $query->leftJoin('product.productImages productImages WITH productImages.Main = true');
        $query->leftJoin('productImages.file file');
        $query->leftJoin('product.productLangs productLangs WITH productLangs.Language_ID = object.Language_ID');
        $query->leftJoin('object.user user');
        $query->leftJoin('user.userSettings userSettings');
        $order = $query->execute()->toArray()[0];

        $totalProducts = 0;
        foreach ( $order['orderItems'] as &$orderItem ) {
            $orderItem['Image'] = fu($orderItem['product']['productImages'][0], 'product/50');
            $orderItem['ProductURL'] = $eshop->URL . '/' . \URL::PRODUCT . '/' . $orderItem['product']['productLangs'][0]['slug'];
            $orderItem['ProductName'] = $orderItem['product']['productLangs'][0]['Name'];
            $orderItem['ProductPrice'] = price($orderItem['PriceWithVat']);
            $orderItem['ProductPriceTotal'] = price($orderItem['PriceWithVat'] * $orderItem['Quantity']);
            $totalProducts += $orderItem['Quantity'];
        }

        $order['TotalProducts'] = $totalProducts;
        $order['PriceTotal'] = price($order['PriceTotalWithVat']);
        $order['OrderStateTypeName'] = $order['orderStateType']['orderStateTypeLangs'][0]['Name'];
        $order['CurrencyMark'] = $eshop->currency->Mark;

        return $order;
    }

