    /**
     * @param array $params
     * @return array|null
     */
    public static function getOrdersByParams(array $params): ?array {
        $date = false;
        if ( isset($params['Date']) && $params['Date'] )
            $date = explode(':', $params['Date']);

        $dateFrom = '1970-01-01';
        if ( isset($date[0]) && $date[0] )
            $dateFrom = $date[0];

        $dateTo = '2100-01-01';
        if ( isset($date[1]) && $date[1] )
            $dateTo = $date[1];

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Order object');

        if ( isset($params['ID']) )
            $query->addWhere('object.ID = ?', $params['ID']);

        if (isset($params['OrderNumber']))
            $query->addWhere('object.OrderNumber LIKE ?', '%' . $params['OrderNumber'] . '%');

        if (isset($params['FullName']))
            $query->addWhere("concat(invoiceAddress.LastName, ' ' , invoiceAddress.FirstName) LIKE ?", $params['FullName']);

        if (isset($params['Email']))
            $query->addWhere('invoiceAddress.OrderNumber Email ?', '%' . $params['Email'] . '%');

        if (isset($params['OrderStateType_ID']) && $params['OrderStateType_ID'])
            $query->addWhere('object.OrderStateType_ID = ?', $params['OrderStateType_ID']);

        if (isset($params['OrderType'])) {
            if ($params['OrderType'] == 'order') {
                $query->addWhere('object.OrderStateType_ID != ?', OrderStateType::ID_STATE_FINISH);
            } else {
                $query->addWhere('object.OrderStateType_ID = ?', OrderStateType::ID_STATE_FINISH);
            }
        }

        $query->addWhere('object.Date >= ?', $dateFrom);
        $query->addWhere('object.Date <= ?', $dateTo);
        $query->leftJoin('object.invoiceAddress invoiceAddress');
        $query->leftJoin('object.orderStateType orderStateType');

        return $query->execute()->toArray();
    }

