            $query->andWhere('object.Date >= ?', $fromDate);

        if ( $orderStateTypeID )
            $query->andWhere('object.OrderStateType_ID = ?', $orderStateTypeID);

        $orders = $query->execute()->toArray();
        $totalSum = 0;

        foreach ( $orders as $order )
