    /**
     * @param string $type
     * @param int $back
     * @return array
     */
    public static function getOrdersChartData(string $type = 'months', int $back = 6): array {
        $connection = Doctrine_Manager::connection();

        if ($type == 'days') {
            $date = date('Y-m-d', strtotime('-'.$back.' days'));
            $query = "CONCAT(DAY(amo.date), '.', MONTH(amo.date))";
            $group = "group by CONCAT(MONTH(amo.date), '-', DAY(amo.date))";
        } elseif ($type == 'months') {
            $date = date('Y-m', strtotime('-'.$back.' months')) . '-01';
            $query = "CONCAT(MONTH(amo.date), '/', YEAR(amo.date))";
            $group = "group by MONTH(amo.date)";
        } elseif ($type == 'quarters') {
            $tmpdate = date('Y-m', strtotime('-'.($back*3).' months')) . '-01';
            $quarter = ceil(date('n', strtotime($tmpdate)) / 3);
            $date = date('Y-m-d', strtotime(date('Y', strtotime($tmpdate)) . '-' . (($quarter * 3) - 2) . '-1'));
            $group = "group by CONCAT(YEAR(amo.date), ' Q', QUARTER(amo.date))";

            $query = "CONCAT(YEAR(amo.date), ' Q', QUARTER(amo.date))";
        }
        $join = '';
        $where = '';

        $eshop = 'AND amo.eshop_id = ' . Eshop::getInstance()->getEshopID();

        $q = 'select ' . $query;
        $q .= " as date,SUM(amo.PriceTotalWithVat) as TotalPrice, COUNT(DISTINCT amo.ID) as TotalCount 
                    from admin__model__order amo 
                    {$join}
                    where amo.date > '{$date}' {$where} {$eshop}
                    {$group}
                    order by date";

        return $connection->execute($q)->fetchAll(PDO::FETCH_ASSOC);
    }

