    /**
     * @param Common_Model_Eshop $eshop
     * @param int $from
     * @param int $to
     * @param int|null $OrderStateTypeID
     * @param string|null $range
     * @return array
     */
    public static function getOrderStats(Common_Model_Eshop $eshop, int $from, int $to, ?int $OrderStateTypeID = null, ?string $range = null): array {
        $orders = [];
        $basic = [
            'Turnover' => 0,
            'TurnoverWithoutVat' => 0,
            'Count' => 0,
        ];

        if (empty($range)) {
            if ($from < strtotime('-6 year',$to)) {
                $groupBy = 'YEAR(object.Date)';
                $start = strtotime(date('Y-01-01', $from));
                while($start < strtotime(date('Y-12-t', $to))) {
                    $orders[date('Y', $start)] = $basic;
                    $start = strtotime('+1 year', $start);
                }
            } elseif ($from < strtotime('-3 year', $to)) {
                $groupBy = 'CONCAT(CEIL(MONTH(object.Date) / 6), "/2 ", YEAR(object.Date))';
                $start = strtotime(date('Y-m-01', $from));
                while($start < strtotime(date('Y-m-t', $to))) {
                    $orders[ceil(date('n') / 6) . '/2 ' . date('Y', $start)] = $basic;
                    $start = strtotime('+6 month', $start);
                }
            } elseif ($from < strtotime('-6 month', $to)) {
                $groupBy = 'CONCAT("Q",CEIL(MONTH(object.Date) / 3), " ", YEAR(object.Date))';
                $start = strtotime(date('Y-m-01', $from));
                while($start < strtotime(date('Y-m-t', $to))) {
                    $orders['Q' . ceil(date('n', $start) / 3) . ' ' . date('Y', $start)] = $basic;
                    $start = strtotime('+3 month', $start);
                }
            } elseif ($from < strtotime('-2 month', $to)) {
                $groupBy = 'CONCAT(MONTH(object.Date),\'. \', YEAR(object.Date))';
                $start = strtotime(date('Y-m-01', $from));
                while($start < strtotime(date('Y-m-t', $to))) {
                    $orders[date('n. Y', $start)] = $basic;
                    $start = strtotime('+1 month', $start);
                }
            } elseif ($from <= strtotime('-14 day', $to)) {
                $groupBy = 'CONCAT(YEAR(object.Date), " ", WEEK(object.Date, 3), \'. týden\')';
                $start = $from;
                while($start < $to) {
                    $orders[date('Y', $start) . ' ' . (date('W', $start)+0) . '. týden'] = $basic;
                    $start = strtotime('+1 week', $start);
                }
            } else {
                $groupBy = 'CONCAT(DAY(object.Date), \'. \', MONTH(object.Date), \'. \', YEAR(object.Date))';
                $start = $from;
                while($start <= $to) {
                    $orders[date('j. n. Y', $start)] = $basic;
                    $start = strtotime('+1 day', $start);
                }
            }
        } else {
            switch ($range) {
                case 'WEEK':
                    $groupBy = 'CONCAT(YEAR(object.Date), " ", WEEK(object.Date, 3), \'. týden\')';
                    $start = $from;
                    while($start < $to) {
                        $orders[date('Y', $start) . ' ' . (date('W', $start)+0) . '. týden'] = $basic;
                        $start = strtotime('+1 week', $start);
                    }
                    break;
                case 'MONTH':
                    $groupBy = 'CONCAT(MONTH(object.Date),\'. \', YEAR(object.Date))';
                    $start = strtotime(date('Y-m-01', $from));
                    while($start < strtotime(date('Y-m-t', $to))) {
                        $orders[date('n. Y', $start)] = $basic;
                        $start = strtotime('+1 month', $start);
                    }
                    break;
                case 'QUARTER':
                    $groupBy = 'CONCAT("Q",CEIL(MONTH(object.Date) / 3), " ", YEAR(object.Date))';
                    $start = strtotime(date('Y-m-01', $from));
                    while($start < strtotime(date('Y-m-t', $to))) {
                        $orders['Q' . ceil(date('n', $start) / 3) . ' ' . date('Y', $start)] = $basic;
                        $start = strtotime('+3 month', $start);
                    }
                    break;
                case 'HALF':
                    $groupBy = 'CONCAT(CEIL(MONTH(object.Date) / 6), "/2 ", YEAR(object.Date))';
                    $start = strtotime(date('Y-m-01', $from));
                    while($start < strtotime(date('Y-m-t', $to))) {
                        $orders[ceil(date('n') / 6) . '/2 ' . date('Y', $start)] = $basic;
                        $start = strtotime('+6 month', $start);
                    }
                    break;
                case 'YEAR':
                    $groupBy = 'YEAR(object.Date)';
                    $start = strtotime(date('Y-01-01', $from));
                    while($start <= strtotime(date('Y-12-t', $to))) {
                        $orders[date('Y', $start)] = $basic;
                        $start = strtotime('+1 year', $start);
                    }
                    break;
                default:
                    $groupBy = 'CONCAT(DAY(object.Date), \'. \', MONTH(object.Date), \'. \', YEAR(object.Date))';
                    $start = $from;
                    while($start <= $to) {
                        $orders[date('j. n. Y', $start)] = $basic;
                        $start = strtotime('+1 day', $start);
                    }
            }
        }

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Order object');
        $query->select('object.Date, object.Eshop_ID, currency.*');
        $query->addSelect('SUM(object.PriceTotalWithVat) Turnover, SUM(object.PriceTotalWithoutVat) TurnoverWithoutVat, COUNT(object.ID) Count');
        $query->addSelect('COUNT(object.ID) Count');
        $query->addSelect($groupBy . ' Date');
        $query->leftJoin('object.currency currency');
        $query->where('object.Date >= "' . date('Y-m-d', $from) . '"');
        $query->andWhere('object.Date <= "' . date('Y-m-d', $to) . '"');
        $query->andWhere('object.Eshop_ID = ?', $eshop->ID);
        if (!empty($OrderStateTypeID))
            $query->andWhere('object.OrderStateType_ID = ?', $OrderStateTypeID);
        $query->groupBy($groupBy);

        $result = $query->execute([], Doctrine_Core::HYDRATE_ARRAY);

        foreach($result as $order) {
            $orders[$order['Date']] = $order;
        }

        return $orders;
    }

