    /**
     * @throws Doctrine_Query_Exception
     */
    public static function getDataForExport($eshopID): array
    {
        $query = Doctrine_Query::create();
        $query->select('o.ID, e.name as eshop, o.ordernumber as ordernumber, v.value as VAT, o.date as date, o.time as time, o.inpohoda as inpohoda, IFNULL(u.name, a.email) as customerName, a.companyname as company, a.ic as ic, a.dic as dic, o.pricetotalwithoutvat as PriceTotalWithoutVAT, o.pricetotalwithvat as PriceTotalWithVAT');
        $query->from('Admin_Model_Order o');
        $query->leftJoin('o.user u WITH u.ID = o.User_ID');
        $query->leftJoin('o.invoiceAddress a WITH a.ID = o.InvoiceAddress_ID');
        $query->leftJoin('o.eshop e WITH e.ID = o.Eshop_ID');
        $query->leftJoin('o.vat v WITH v.ID = o.Vat_ID');
        $query->where('o.Eshop_ID=?', $eshopID);
        $query->groupBy('o.ID');

        $orderData = $query->execute([], Doctrine_Core::HYDRATE_ARRAY);
        $result = [];
        $i = 0;

        foreach ($orderData as &$data) {
            $result[$i]['E-shop'] = $data['eshop'];
            $result[$i]['OrderNumber'] = $data['ordernumber'];
            $result[$i]['VAT'] = $data['VAT'] ?? '';
            $result[$i]['Date'] = $data['date'];
            $result[$i]['Time'] = $data['time'];
            $result[$i]['InPohoda'] = $data['inpohoda'];
            $result[$i]['CustomerName'] = $data['customerName'];
            $result[$i]['Company'] = $data['company'];
            $result[$i]['IC'] = $data['ic'];
            $result[$i]['DIC'] = $data['dic'];
            $result[$i]['PriceTotalWithoutVAT'] = $data['PriceTotalWithoutVAT'];
            $result[$i]['PriceTotalWithVAT'] = $data['PriceTotalWithVAT'];

            $i++;
        }
        return $result;
    }

    /**
     * Vrací kupón
     * @return Coupon|null
     */
    public function getCoupon(): ?Coupon {
        return $this->coupon?$this->coupon:null;
    }

    private function applyCoupon(Cart $cart) {
        if (!$cart->coupon)
            return;

        $coupon = Admin_Model_Coupon::getCouponByCode($cart->getCoupon(), $cart->totalPriceWithoutCoupon);

        if (!$coupon)
            return;

        $this->coupon = $coupon;
        $this->coupon->use();

        if ($this->coupon->Type == Coupon::TYPE_ITEM && $this->coupon->Product_ID) {
            $orderItem = new OrderItem();
            $orderItem->Order_ID = $this->ID;
            $orderItem->Product_ID = $this->coupon->Product_ID;
            $orderItem->Quantity = $this->coupon->Quantity;
            $orderItem->PriceWithoutVat = 0;
            $orderItem->PriceWithVat = 0;
            $orderItem->Vat = 21.00;
            $orderItem->save();
        }

        $this->save();
    }

    /**
     * @return float|false|float|int
     */
    public function getCouponDiscount() {
        if (!$this->coupon || !$this->coupon->IsDiscount())
            return 0;

        if ($this->coupon->Type === $this->coupon::TYPE_DISCOUNT)
            return $this->coupon->Discount;

        if ($this->coupon->Type === $this->coupon::TYPE_PERCENTAGE) {
            $price = $this->WithoutVat?$this->PriceProductWithoutVat:$this->PriceProductWithVat;
            $discount = (100 - $this->coupon->Discount) / 100;

            return floor((float) $price / $discount) - (float) $price;
        }

        return 0;
    }

