        $query->from('Admin_Model_Order object');
        $query->leftJoin('object.orderItems orderItems');
        $query->leftJoin('object.payment payment');
        $query->leftJoin('object.currency currency');
        $query->leftJoin('object.orderStateType orderStateType');
        $query->leftJoin('orderStateType.orderStateTypeLangs orderStateTypeLangs WITH orderStateTypeLangs.language_ID = ?',  $eshop->getEshop()->Language_ID);
        $query->where('object.User_ID=?', $userID);
        $query->andWhereNotIn('object.OrderStateType_ID', [5,4]);
        return $query->execute()->toArray();
    }

