        $query->leftJoin('product.productLangs productLangs WITH productLangs.Language_ID = object.Language_ID');
        $query->leftJoin('object.user user');
        $query->leftJoin('user.userSettings userSettings');

        return $query->execute()->toArray();
    }

    public static function updatePPLParcelInfo($orderID, $packageID)
    {
        $trackingUrl = 'https://www.ppl.cz/vyhledat-zasilku?shipmentId=' . $packageID;
        $query = Doctrine_Query::create();
        $query->update('Admin_Model_Order');
        $query->set('ParcelNumber', '?', $packageID);
        $query->set('TrackingUrl', '?', $trackingUrl);
        $query->where('ID=?', $orderID);
        $query->execute();
    }

